import { Component, OnInit } from "@angular/core";
import {
  FormBuilder,
  FormControl,
  FormGroup,
  Validators,
} from "@angular/forms";
import { User } from "src/app/views/Models/Users/User";
import { pagingService } from "src/app/core/services/paging.service";
import { sortingService } from "src/app/core/services/sorting.service";
import { HttpClient } from "@angular/common/http";
import { EnvService } from "src/app/core/services/env.service";
import { MohassilAuthService } from "src/app/core/services/AuthenticationServices/mohassil-auth.service";
import { AlertService } from "src/app/core/services/alert.service";
import { Report } from "src/app/views/Models/Reports/Report";
import { PdfViewerService } from "src/app/core/services/pdf-viewer.service";
import { LoansService } from "src/app/core/services/loans.service";
import { trigger, transition, style, animate } from "@angular/animations";
import { VendorForUser } from "src/app/views/Models/Settings/Vendor";
import {
  ConsumerLoanItemsRespons,
  ConsumerLoansListRespons,
} from "src/app/views/Models/Loan/ConsumerLoansRespons";
import { saveAs } from "file-saver";
import { atobSafe } from "src/app/core/util/atobSafe";

@Component({
  selector: "app-loan-items",
  templateUrl: "./loan-items.page.html",
  styleUrls: ["./loan-items.page.scss"],
  animations: [
    trigger("slideFadeIn", [
      transition(":enter", [
        style({ transform: "translateY(-20px)", opacity: 0 }), // 👈 Start above
        animate(
          "300ms ease-out",
          style({ transform: "translateY(0)", opacity: 1 }) // 👈 Move to position
        ),
      ]),
      transition(":leave", [
        animate(
          "200ms ease-in",
          style({ transform: "translateY(-20px)", opacity: 0 }) // 👈 Move back up
        ),
      ]),
    ]),
  ],
})
export class LoanItemsPage implements OnInit {
  // LOAN-ITEMS
  VendorForUsers: VendorForUser[] = [];
  constructor(
    public formBuilder: FormBuilder,
    public pagingService: pagingService,
    private sortingService: sortingService,
    private LoansService: LoansService,
    private env: EnvService,
    private http: HttpClient,
    private authService: MohassilAuthService,
    private alertService: AlertService,
    private pdfViewerService: PdfViewerService
  ) {}

  //region VARIABLES
  showLoader: boolean = false;
  isParametersFormValid: boolean = false;
  showDataGrid: boolean = false;
  consumerLoansListResponsModel: ConsumerLoansListRespons[] = [];
  consumerLoanItemsResponsModel: ConsumerLoanItemsRespons[] = [];
  selectedLoanRowIndex: number = -1;
  selectedItemRowIndex: number = -1;
  sortingIconParam: string;
  sortingIconClass: string = "arrow-down-outline";
  selectedVendors: string;
  org_code_user_info: string;
  user_name: string;
  reportsLabels: Array<{ key: number; value: string }>;
  showReportButton: boolean = false;
  pagingObject: { pageSize: number; page: number }; // = { page: 1, pageSize: 3 };
  isModalOpen = false;
  client_name: string;
  nation_id: string;
  client_gender_desc: string;
  client_status_desc: string;
  vendor_name: string;
  vendor_br_name: string;
  loan_type_name: string;
  loan_status_desc: string;
  loan_date: string;
  loan_am: string;
  loan_int_rt: string;
  loan_items_grand_total_price: string;
  application_keys: string;
  application_keys_for_csv: string[];
  items_counter: number;
  full_loan_code: string;
  //End region

  async ngOnInit() {
    this.pagingObject = {
      pageSize: this.pagingService.getPageSizeFromLocalStorage(),
      page: 1,
    };
    this.authService.getUserInfo().then((userInfo) => {
      this.org_code_user_info = userInfo.org_code;
      this.user_name = userInfo.user_name;
      this.getVendorsForUser(userInfo.user_name);
    });
    this.reportsLabels = [{ key: 1, value: "سلع القروض الاستهلاكية للعملاء" }];
  }

  //region FORMS
  parametersForm: FormGroup = this.formBuilder.group({
    vendor_code: ["", Validators.required],
    loan_date_start: [
      "",
      [
        Validators.required,
        Validators.pattern(
          "((?:19|20)\\d\\d)-(0?[1-9]|1[012])-([12][0-9]|3[01]|0?[1-9])"
        ),
        this.noDateGreaterToday,
      ],
    ],
    loan_date_end: [
      "",
      [
        Validators.required,
        Validators.pattern(
          "((?:19|20)\\d\\d)-(0?[1-9]|1[012])-([12][0-9]|3[01]|0?[1-9])"
        ),
        this.noDateGreaterToday,
      ],
    ],
    rep_flag: ["", Validators.required],
  });
  get GetParametersForm() {
    return this.parametersForm.controls;
  }

  //region FORM VALIDATION
  // LOAN-ITEMS
  // DONE
  noDateGreaterToday(control: FormControl) {
    const isDateGrater = new Date(control.value);
    const currentDate = new Date();
    if (isDateGrater > currentDate) {
      return { DateIsGrater: true };
    }
  }

  //region FORM TOOLS
  // LOAN-ITEMS
  // DONE
  clear() {
    this.consumerLoansListResponsModel = [];
    this.selectedVendors = "";
    this.showReportButton = false;
    this.pagingObject.page = 1;
    this.showDataGrid = false;
    this.selectedLoanRowIndex = -1;
    this.selectedItemRowIndex = -1;
    this.application_keys = "";
    this.application_keys_for_csv = [];
  }

  // LOAN-ITEMS
  // DONE
  selectLoanGridRow(index: number) {
    this.selectedLoanRowIndex = index;
  }
  // LOAN-ITEMS
  // DONE
  selectItemGridRow(index: number) {
    this.selectedItemRowIndex = index;
  }

  // LOAN-ITEMS
  // DONE
  getRowClassesItemsGrid(index: number): string[] {
    const isSelected = this.selectedItemRowIndex === index;
    if (isSelected) return ["highlighted-row"];
    return [];
  }

  // LOAN-ITEMS
  // DONE
  getRowClassesLoansGrid(index: number): string[] {
    const isSelected = this.selectedLoanRowIndex === index;
    if (isSelected) return ["highlighted-row"];
    return [];
  }

  // LOAN-ITEMS
  // DONE
  sortingTable(data: any, param: string) {
    this.sortingService.sortByParameter(data, param);
    this.sortingIconClass =
      this.sortingService.sortOrder === "asc"
        ? "arrow-down-outline"
        : "arrow-up-outline";
    this.sortingIconParam = param;
  }

  // LOAN-ITEMS
  changePaginationPage = (newPage: number): void => {
    this.pagingObject.page = newPage;
    this.selectedLoanRowIndex = -1;
    this.selectedItemRowIndex = -1;
  };

  // region DATA GETTERS
  // LONA-ITEMS
  // DONE
  async getConsumerLoansList() {
    this.isParametersFormValid = true;
    if (
      this.parametersForm.controls.loan_date_end.value <
      this.parametersForm.controls.loan_date_start.value
    ) {
      this.alertService.showAlertError(
        "لا يمكن اختيار تاريخ النهاية اصغر من تاريخ البداية",
        null
      );
    } else if (this.parametersForm.valid) {
      this.showLoader = true;
      this.clear();

      this.consumerLoansListResponsModel =
        await this.LoansService.getConsumerLoans(
          this.parametersForm.controls.vendor_code.value,
          this.parametersForm.controls.loan_date_start.value,
          this.parametersForm.controls.loan_date_end.value,
          this.parametersForm.controls.rep_flag.value
        );
      this.collectParamsStrings();
      this.application_keys_for_csv = this.consumerLoansListResponsModel.map(
        (key) => key.application_key
      );
      if (this.consumerLoansListResponsModel.length != 0) {
        this.showDataGrid = true;
        this.showReportButton = true;
      } else {
        this.alertService.showAlertError(
          "لا يوجد نتيجة بناء على الخصائص المختارة",
          null
        );
        this.showReportButton = false;
      }
      this.showLoader = false;
    }
  }

  // LONA-ITEMS
  // DONE
  async getLoanItems(application_key: string) {
    if (application_key) {
      this.showLoader = true;
      this.consumerLoanItemsResponsModel =
        await this.LoansService.getConsumerLoanItems(application_key);
      this.showLoader = false;
      this.setOpen(true);
    }
    // PATCH DATA FOR ITEMS MODAL
    this.client_name = this.consumerLoanItemsResponsModel[0]["client_name"];
    this.nation_id = this.consumerLoanItemsResponsModel[0]["nation_id"];
    this.client_gender_desc =
      this.consumerLoanItemsResponsModel[0]["client_gender_desc"];
    this.client_status_desc =
      this.consumerLoanItemsResponsModel[0]["client_status_desc"];
    this.vendor_name = this.consumerLoanItemsResponsModel[0]["vendor_name"];
    this.vendor_br_name =
      this.consumerLoanItemsResponsModel[0]["vendor_br_name"];

    this.items_counter = this.consumerLoanItemsResponsModel.length;
    this.loan_type_name =
      this.consumerLoanItemsResponsModel[0]["loan_type_name"];
    this.loan_date = this.consumerLoanItemsResponsModel[0]["loan_date"];
    this.loan_am = this.consumerLoanItemsResponsModel[0]["loan_am"];
    this.loan_int_rt = this.consumerLoanItemsResponsModel[0]["loan_int_rt"];
    this.loan_items_grand_total_price =
      this.consumerLoanItemsResponsModel[0]["loan_items_grand_total_price"];
    this.full_loan_code =
      this.consumerLoanItemsResponsModel[0]["loan_code"] +
      " / " +
      this.consumerLoanItemsResponsModel[0]["client_code"] +
      " / " +
      this.consumerLoanItemsResponsModel[0]["org_branch_code"];
    this.loan_status_desc =
      this.consumerLoanItemsResponsModel[0]["loan_status_desc"];
  }

  //region FORM ACTIONS
  // LOAN-ITEMS
  // DONE
  collectParamsStrings() {
    this.selectedVendors =
      this.parametersForm.controls.vendor_code.value.join(`,`);
    this.application_keys = this.consumerLoansListResponsModel
      .map((loan) => [loan.application_key])
      .join(`,`);
  }

  //region GET REPORT
  // DONE
  private b64DecodeUnicode(str): string {
    return decodeURIComponent(
      atobSafe(str)
        .split("")
        .map(function (c) {
          return "%" + ("00" + c.charCodeAt(0).toString(16)).slice(-2);
        })
        .join("")
    );
  }

  // LOAN-ITEMS
  // DONE
  GetConsumerLoansItemsCSV() {
    this.showLoader = true;
    this.http
      .post(
        this.env.API_URL + `api/Loan/GetConsumerLoanItemsForCSV`,
        {
          application_keys: this.application_keys_for_csv,
        },
        { responseType: "blob" }
      )
      .subscribe({
        next: (response: Blob) => {
          const currentDate = new Date();
          const dateString = currentDate.toLocaleDateString("en-US");
          const timeString = currentDate.toLocaleTimeString("en-US", {
            hour: "numeric",
            minute: "numeric",
            hour12: false,
          });
          const formattedDateTime = `${dateString} ${timeString}`;

          const filename =
            formattedDateTime + " " + "ConsumerLoansItemsDetails.csv";
          const options = { autoBom: false };
          this.showLoader = false;
          saveAs(response, filename, options);
          this.showLoader = false;
        },
        error: (err) => {
          console.log(err);
        },
      });
  }

  // LOAN-ITEMS
  // DONE
  public async getReport(Report: string) {
    let ReportValue = Report;
    if (ReportValue == "" || !!!ReportValue) {
      this.alertService.showAlertError("يجب اختيار نوع تقرير", false, "موافق");
    } else {
      let reportName: string;
      let reportParameter: Array<{ key: string; value: string }> = [];
      switch (ReportValue) {
        case "1":
          if (this.application_keys.length != 0) {
            if (this.sortingIconParam == undefined) {
              this.sortingIconParam = "row_num";
            }
            reportName = "consumer_get_loan_items_report";
            reportParameter = [
              {
                key: "@application_keys",
                value: this.application_keys,
              },
            ];
          } else {
            this.alertService.showAlertError(
              "يجب اختيار طلبات قروض للعرض",
              false
            );
          }
          break;
        // case "2":
        //   if (this.selectedLoan.length != 0) {
        //     reportName = "";
        //     reportParameter = [
        //       {
        //         key: "@",
        //         value: ,
        //       },
        //     ];
        //   } else {
        //     this.alertService.showAlertError(
        //       "يجب اختيار طلبات قروض للعرض",
        //       false
        //     );
        //   }
        //   break;
      }
      let token = await this.authService.getAccessToken();
      token = token.replace("-", "+").replace("_", "/");
      const claims = JSON.parse(atobSafe(token.split(".")[1]));
      let username: string = "";
      let pwd: string = "";
      try {
        username = this.b64DecodeUnicode(btoa(claims.user_name));
      } catch (err) {
        username = claims.user_name;
      }
      try {
        pwd = this.b64DecodeUnicode(btoa(claims.pwd));
      } catch (err) {
        pwd = claims.pwd;
      }
      this.showLoader = true;
      this.http
        .post<Report>(this.env.API_URL + `api/Reporting/GetReport`, {
          report_name: reportName,
          report_parameters: reportParameter,
          token: {
            username: username,
            password: pwd,
          },
        })
        .subscribe({
          next: async (data) => {
            this.showLoader = false;
            if (data.status_code == 200) {
              this.showClientReportPdf(data.report!, null);
            } else {
              await this.alertService.showAlertError(data.message, false);
            }
          },
          error: async (err) => {
            await this.alertService.showAlertError(err.error, false);
            this.showLoader = false;
          },
        });
    }
  }

  public async showClientReportPdf(pdfBase64: string, client_name: string) {
    if (!this.pdfViewerService.canViewPdf()) {
      await this.alertService.showAlertError(
        "لا يمكن عرض أو تنزيل المستند على المتصفح الحالي",
        false
      );
      return;
    }
    let reportlabel = this.reportsLabels.find(
      (x) => x.key == 1 //this.ReportForm.controls.reportValue.value
    ).value;
    await this.pdfViewerService.viewPdf(
      pdfBase64!,
      `تقرير ${{ reportlabel }} - ${{ client_name }}.pdf`,
      reportlabel
    );
  }

  //region ITEMS MODAL
  // LOAN-ITEMS
  // DONE
  setOpen(isOpen: boolean) {
    this.isModalOpen = isOpen;
    this.clearItemsModal();
  }

  // LOAN-ITEMS
  // DONE
  clearItemsModal() {
    if (this.isModalOpen == false) {
      this.client_name = "";
      this.nation_id = "";
      this.client_gender_desc = "";
      this.client_status_desc = "";
      this.consumerLoanItemsResponsModel = [];
      this.selectedItemRowIndex = -1;
    }
  }

  // LOAN-ITEMS
  // DONE
  getVendorsForUser(user: string): void {
    this.showLoader = true;
    this.http
      .get<VendorForUser[]>(
        this.env.API_URL + `api/Settings/GetVendorsByUser?user_name=${user}`
      )
      .subscribe({
        next: (data) => {
          this.VendorForUsers = data;
          this.showLoader = false;
        },
        error: (err) => {
          this.showLoader = false;
        },
      });
  }
}
